import{_ as o,c,o as d,ae as a}from"./chunks/framework.Cd-3tpCq.js";const p=JSON.parse('{"title":"自用前端命名规范","description":"","frontmatter":{},"headers":[],"relativePath":"articles/frontend-naming-conventions.md","filePath":"articles/frontend-naming-conventions.md","lastUpdated":1755926199000}'),l={name:"articles/frontend-naming-conventions.md"};function i(t,e,r,s,n,u){return d(),c("div",null,e[0]||(e[0]=[a('<h1 id="自用前端命名规范" tabindex="-1">自用前端命名规范 <a class="header-anchor" href="#自用前端命名规范" aria-label="Permalink to &quot;自用前端命名规范&quot;">​</a></h1><h2 id="typescript-类型命名" tabindex="-1">TypeScript 类型命名 <a class="header-anchor" href="#typescript-类型命名" aria-label="Permalink to &quot;TypeScript 类型命名&quot;">​</a></h2><ul><li>Interface: 使用 I 前缀（如 <code>IConfig</code>, <code>ILoader</code>, <code>IDevServerConfig</code>）。 <ul><li><strong>如果接口为公共或基础接口，建议在名称中包含 <code>Base</code> 或 <code>Public</code> 字样</strong>（如 <code>IBaseOptions</code>, <code>IPublicFormDataType</code>），以便一目了然地识别其用途和继承关系。</li></ul></li><li>Type: 使用 T 前缀（如 <code>TBuildMode</code>, <code>TAssetInfo</code>, <code>TLoaderResult</code>）。</li><li>Enum：使用 E 前缀（如 <code>EBuildStatus</code>, <code>ELoaderType</code>, <code>EHMREvent</code>）。</li><li>Enum 成员：使用 UPPER_SNAKE_CASE（如 <code>SUCCESS</code>, <code>FAILURE</code>, <code>PENDING</code>）。</li><li>Generic 泛型：使用单个大写字母，从 T 开始（如 <code>T</code>, <code>U</code>, <code>K</code>, <code>V</code>），如需表达更复杂含义可用 PascalCase 组合词（如 <code>TResultData</code>、<code>TOptions</code>），集合类泛型可用复数（如 <code>TItems</code>）。</li><li>Interface 主要用于结构描述（如对象的属性、方法等），Type 适合联合类型、交叉类型、条件类型等更复杂场景。接口支持声明合并，类型别名不支持。</li><li>命名空间与模块（namespace/module）：使用 PascalCase（如 <code>Utils</code>, <code>ConfigParser</code>）。</li></ul><h3 id="为什么要在类型前面加前缀" tabindex="-1">为什么要在类型前面加前缀？ <a class="header-anchor" href="#为什么要在类型前面加前缀" aria-label="Permalink to &quot;为什么要在类型前面加前缀？&quot;">​</a></h3><p><strong>尽管</strong>这种做法并不被广泛推荐，<strong>但在很多情况下</strong>，为了明确区分业务相关的组件、变量和服务与 TypeScript 类型，采用前缀可以提供清晰的标识。例如，在先前的一些项目中，尤其是基于 Node.js 后端以及使用 React 的前端项目，许多实体均采用了大驼峰命名法。为了进一步增强代码的可读性和维护性，通过为 TypeScript 类型和接口添加 <code>T</code> 和 <code>I</code> 前缀，能够有效避免混淆，确保开发过程中对不同类型元素的识别<strong>更加直观准确</strong>。</p><h2 id="代码命名规范" tabindex="-1">代码命名规范 <a class="header-anchor" href="#代码命名规范" aria-label="Permalink to &quot;代码命名规范&quot;">​</a></h2><ul><li>常量: 使用 UPPER_SNAKE_CASE（如 <code>DEFAULT_PORT</code>, <code>MAX_THREADS</code>, <code>BUILD_TIMEOUT</code>），全局常量建议加模块前缀（如 <code>BUILD_DEFAULT_PORT</code>）。</li><li>私有方法: 使用 <code>_</code> 前缀（如 <code>_processModule</code>, <code>_handleError</code>, <code>_validateConfig</code>）。</li><li>类名: 使用 PascalCase（如 <code>Compiler</code>, <code>DevServer</code>, <code>AssetLoader</code>）。 <ul><li><strong>如果类为基础类或公共基类，建议名称中包含 <code>Base</code> 或 <code>Abstract</code> 字样</strong>（如 <code>BaseController</code>, <code>AbstractService</code>），便于识别继承体系。</li></ul></li><li>函数/变量: 使用 camelCase（如 <code>buildProject</code>, <code>configPath</code>, <code>moduleInfo</code>）。 <ul><li><strong>不限制名称长度，推荐根据实际用途使用有意义且描述性强的长名称</strong>，如 <code>getUserProfileByIdAsync</code>、<code>defaultUserAvatarUrl</code>，好的名字比注释更直观。</li></ul></li><li>未使用的参数: 使用 <code>_</code> 前缀，防止产生歧义（如 <code>array.map((_item, index) =&gt; index * 2)</code>）。当只用第二或后续参数时，前面未用参数也应加 <code>_</code> 前缀。</li><li>文件名: 使用 kebab-case（如 <code>build-config.ts</code>, <code>dev-server.ts</code>, <code>asset-loader.ts</code>），避免与保留字、已有 npm 包重名。</li><li>目录名: 使用 kebab-case（如 <code>build-tools/</code>, <code>config-parser/</code>, <code>utils/</code>），避免单字符目录名。</li><li>测试文件命名： <ul><li>单元测试文件建议以 <code>.spec.ts</code> 结尾（如 <code>math-utils.spec.ts</code>），用于测试单个函数、类、模块的行为。</li><li>集成测试或端到端测试文件建议以 <code>.test.ts</code> 结尾（如 <code>api-integration.test.ts</code>），用于测试多个模块协作或完整业务流程。</li></ul></li><li>缩写统一大写（如 <code>APIClient</code>, <code>HTMLParser</code>），避免 <code>ApiClient</code>、<code>HtmlParser</code> 等写法，且避免无意义缩写。</li><li>异步函数建议以 Async 结尾或用动词前缀（如 <code>fetchDataAsync</code>, <code>getUserInfo</code>）。</li><li>React 组件名用 PascalCase，hooks 用 use 前缀（如 <code>useUserInfo</code>）。</li><li>类型守卫函数统一用 isXxx 命名（如 <code>isString</code>）。</li></ul><h2 id="布尔值命名规范" tabindex="-1">布尔值命名规范 <a class="header-anchor" href="#布尔值命名规范" aria-label="Permalink to &quot;布尔值命名规范&quot;">​</a></h2><ul><li>使用 <code>is</code>, <code>has</code>, <code>can</code>, <code>should</code>, <code>will</code> 等前缀（如 <code>isLoading</code>, <code>hasError</code>, <code>canBuild</code>, <code>shouldOptimize</code>），避免 <code>isNotX</code>、<code>flagX</code> 等反模式，布尔变量应表达正向含义。</li></ul><h2 id="事件和回调命名" tabindex="-1">事件和回调命名 <a class="header-anchor" href="#事件和回调命名" aria-label="Permalink to &quot;事件和回调命名&quot;">​</a></h2><ul><li>事件处理函数: 使用 <code>handle</code> 或 <code>on</code> 前缀（如 <code>handleClick</code>, <code>onFileChange</code>），事件名用 PascalCase（如 <code>onUserLogin</code>）。</li><li>回调函数: 使用描述性动词（如 <code>onComplete</code>, <code>onError</code>, <code>beforeBuild</code>），回调参数用 <code>event</code> 结尾（如 <code>onChangeEvent</code>）。</li></ul><h2 id="模块导出命名" tabindex="-1">模块导出命名 <a class="header-anchor" href="#模块导出命名" aria-label="Permalink to &quot;模块导出命名&quot;">​</a></h2><ul><li>默认导出: 使用文件主要功能的名称</li><li>命名导出: 使用具体的功能名称</li><li>重新导出: 保持原有命名或使用 <code>as</code> 重命名以避免冲突。</li></ul><h2 id="其他" tabindex="-1">其他 <a class="header-anchor" href="#其他" aria-label="Permalink to &quot;其他&quot;">​</a></h2><ul><li>变量声明一行一个（如 <code>let a = 1; let b = 2;</code>），避免 <code>let a = 1, b = 2;</code>。</li><li>优先使用箭头函数，必要时再用 <code>function</code>。</li><li>花括号、缩进等风格细节可参考微软官方规范（如 4 空格缩进，else 单独一行）。</li><li>测试描述（describe/it）用英文，表达行为和预期结果。</li><li>类型断言建议谨慎使用，优先类型收窄。</li><li>代码注释建议用 TSDoc 风格，除非这个模块不用 TS 而用 JS。</li></ul>',15)]))}const f=o(l,[["render",i]]);export{p as __pageData,f as default};
